std::string max_value_key(const std::vector<std::string>& keys, const std::vector<int>& vals){
    std::map<std::string,int> m;
    for (size_t i = 0; i < keys.size(); ++i) m[keys[i]] += vals[i];
    std::string best = "";
    int best_val = -2147483647;
    for (std::map<std::string,int>::iterator it = m.begin(); it != m.end(); ++it){
        if (it->second > best_val){ best_val = it->second; best = it->first; }
    }
    return best;
}

